// 2. Extract required fields from the 'dates' object
const start_time = $('NLP Date Parser').first().json.dates[0].start;
const end_time = $('NLP Date Parser').first().json.dates[0].end;
const timezone = $('NLP Date Parser').first().json.dates[0].timezone;

// 3. Create a separate block with time information
const time_info = `
Time Information: 
---
Start: ${start_time}
End: ${end_time}
Timezone: ${timezone}
transfer values to time parameters do not change them
`;

// 4. Add time information to the main agent input
const user_input = `
${time_info}
---
Chat History:
---
${history}
---
Cached Context (Previous Search Results):
---
${cached_context}
---
New User Query: "${user_query}"
`;

return { user_input, original_query: user_query };

// Purpose: Safely extract and parse JSON from the LLM response.

try {
  // 1. Get text content from OpenAI response
  const content = $input.first().json.output;

  // 2. Use regex to find the JSON object within the text.
  // Protects against extra text like "Here is the JSON: ..."
  const jsonMatch = content.match(/\{[\s\S]*\}/);

  if (jsonMatch && jsonMatch[0]) {
    // 3. Parse and return if JSON is found
    return JSON.parse(jsonMatch[0]);
  } else {
    // Throw error to trigger catch block if JSON not found
    throw new Error("No valid JSON object found in the LLM response.");
  }

} catch (error) {
  // 4. On error (invalid or missing JSON),
  // return a safe default object to keep the workflow running.
  // Tells the system to skip the new search.
  console.error("Failed to parse JSON from LLM response:", error);
  return {
    needs_search: false,
    search_parameters: null
  };
}

